function pick(node) {
  const f = $(`${node}`).first().json?.data?.list?.[0];
  return f ? { id: f.id, isin: f.scheme_isin, name: f.name, short: f.name?.split(' - ')[0] } : null;
}
return [{ json: { largeCap: pick('Fetch Large Cap Funds'), flexiCap: pick('Fetch Flexi Cap Funds'), midCap: pick('Fetch Mid Cap Funds') } }];

const ids = $('Extract Fund IDs').first().json;
function getH(node) { return $(`${node}`).first().json?.data?.holdings ?? []; }

const funds = [
  { name: ids.largeCap?.short ?? 'Large Cap', h: getH('Holdings: Large Cap') },
  { name: ids.flexiCap?.short ?? 'Flexi Cap', h: getH('Holdings: Flexi Cap') },
  { name: ids.midCap?.short   ?? 'Mid Cap',   h: getH('Holdings: Mid Cap') }
];

// holding-changes fields: security_name, latest_weight, industry, status, absolute_change
// Use latest_weight as portfolio weight — works for all 4 strategies

// --- S1: Conviction Clustering (held at ≥2% by 2+ AMCs) ---
const cmap = {};
funds.forEach(fund => {
  const sorted = [...fund.h].sort((a,b)=>(b.latest_weight??0)-(a.latest_weight??0));
  sorted.forEach((h, idx) => {
    const wt = h.latest_weight ?? 0;
    if (wt < 2) return;
    const k = h.security_name;
    if (!cmap[k]) cmap[k] = { stock: k, sector: h.industry, amcs: [], weights: [], total: 0 };
    cmap[k].amcs.push(fund.name); cmap[k].weights.push(wt); cmap[k].total += wt;
  });
});
const conviction = Object.values(cmap).filter(s=>s.amcs.length>=2).map(s=>{
  const avg = s.total/s.amcs.length;
  const score = parseFloat((avg*s.amcs.length).toFixed(2));
  const conf  = Math.min(100, Math.round((s.amcs.length/3)*40 + Math.min(40,avg*4) + 20));
  return { stock:s.stock, sector:s.sector, amc_count:s.amcs.length, amcs:s.amcs,
           avg_weight:parseFloat(avg.toFixed(2)), conviction_score:score, confidence:conf };
}).sort((a,b)=>b.conviction_score-a.conviction_score).slice(0,8);

// --- S2: Alpha Basket ---
const bmap = {};
funds.forEach(fund=>{
  fund.h.forEach(h=>{
    const wt=h.latest_weight??0;
    if(!bmap[h.security_name]) bmap[h.security_name]={stock:h.security_name,sector:h.industry,total:0,count:0};
    bmap[h.security_name].total+=wt; bmap[h.security_name].count+=1;
  });
});
const basket = Object.values(bmap).map(s=>({stock:s.stock,sector:s.sector,
  score:parseFloat((s.count*(s.total/s.count)).toFixed(2))})).sort((a,b)=>b.score-a.score).slice(0,10);

// --- S3: Sector Flow ---
const fall = [
  ...getH('Holdings: Large Cap'), ...getH('Holdings: Flexi Cap'), ...getH('Holdings: Mid Cap')
];
const fmap = {};
fall.forEach(h=>{
  const sec=h.industry||h.bucket||'Other';
  const chg=h.absolute_change??0;
  if(!fmap[sec]) fmap[sec]={sector:sec,net:0,added:0,removed:0,drivers:[]};
  fmap[sec].net+=chg;
  if(h.status==='added')   fmap[sec].added++;
  if(h.status==='removed') fmap[sec].removed++;
  if(Math.abs(chg)>0.1)   fmap[sec].drivers.push({stock:h.security_name,chg:parseFloat(chg.toFixed(2))});
});
const sectors = Object.values(fmap).filter(s=>s.sector!=='Other').map(s=>({
  ...s, net:parseFloat(s.net.toFixed(2)),
  drivers:s.drivers.sort((a,b)=>Math.abs(b.chg)-Math.abs(a.chg)).slice(0,3)
})).sort((a,b)=>b.net-a.net).slice(0,8);

// --- S4: New Entries across 2+ AMCs ---
const nmap = {};
funds.forEach(({name,h})=>{
  h.filter(x=>x.status==='added').forEach(x=>{
    if(!nmap[x.security_name]) nmap[x.security_name]={stock:x.security_name,sector:x.industry,amcs:[],max_wt:0};
    nmap[x.security_name].amcs.push({fund:name,wt:x.latest_weight??0});
    if((x.latest_weight??0)>nmap[x.security_name].max_wt) nmap[x.security_name].max_wt=x.latest_weight??0;
  });
});
const newEntries = Object.values(nmap).filter(s=>s.amcs.length>=2)
  .sort((a,b)=>b.amcs.length-a.amcs.length||b.max_wt-a.max_wt).slice(0,8);

return [{ json: { funds:funds.map(f=>f.name), conviction, basket, sectors, newEntries, generated:new Date().toISOString() } }];

const d = $input.first().json;
const { conviction=[], basket=[], sectors=[], newEntries=[], funds=[], generated='' } = d;
const maxFlow = Math.max(...sectors.map(function(s){ return Math.abs(s.net); }), 1);

// Build sector bars HTML without nested template literals
const sectorBarsHtml = sectors.map(function(s) {
  const pct = Math.max(2, Math.round((Math.abs(s.net) / maxFlow) * 100));
  const pos  = s.net >= 0;
  const drvr = s.drivers.map(function(d) {
    return d.stock.split(' ')[0] + '(' + (d.chg > 0 ? '+' : '') + d.chg + '%)';
  }).join(' · ');
  const barClass = pos ? 'sp' : 'sn';
  const valColor = pos ? '#10b981' : '#ef4444';
  const sign     = pos ? '+' : '';
  return '<div class="srow">'
    + '<span class="sname">' + s.sector + '</span>'
    + '<div class="sbwrap"><div class="sbar ' + barClass + '" style="width:' + pct + '%">' + sign + s.net + '%</div></div>'
    + '<span class="sval" style="color:' + valColor + '">' + sign + s.net + '%</span>'
    + '</div>'
    + (drvr ? '<div class="sdrvr">↳ ' + drvr + '</div>' : '');
}).join('');

// Build signal cards without nested template literals
const signalCardsHtml = newEntries.length
  ? newEntries.map(function(s) {
      const hi = s.amcs.length >= 3;
      const bdgClass = hi ? 'bh' : 'bm';
      const bdgLabel = (hi ? '🔴 HIGH' : '🟡 MEDIUM') + ' · ' + s.amcs.length + ' AMCs';
      const amcNames = s.amcs.map(function(a){ return a.fund; }).join(' · ');
      return '<div class="sc">'
        + '<div class="sn2">' + s.stock + '</div>'
        + '<span class="bdg ' + bdgClass + '">' + bdgLabel + '</span>'
        + '<div class="amc">' + amcNames + '</div>'
        + '<div class="wt">Max: ' + s.max_wt.toFixed(2) + '% · Hold 60d</div>'
        + '</div>';
    }).join('')
  : '<p style="color:#475569;font-size:12px">No cross-AMC new entries this month.</p>';

// Chart data as JSON strings (safe to embed)
const convJson    = JSON.stringify(conviction);
const basketJson  = JSON.stringify(basket);
const sectorsJson = JSON.stringify(sectors);
const newJson     = JSON.stringify(newEntries);
const fundsHtml   = funds.map(function(f){ return '<span class="tag">' + f + '</span>'; }).join('');

const html = '<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><title>MF Alpha Dashboard</title>'
  + '<script src="https://cdn.jsdelivr.net/npm/chart.js@4.4.0/dist/chart.umd.min.js"><\/script>'
  + '<style>'
  + '*{margin:0;padding:0;box-sizing:border-box}body{font-family:Segoe UI,sans-serif;background:#0f172a;color:#e2e8f0}'
  + '.hdr{background:linear-gradient(135deg,#1e3a5f,#0f172a);padding:20px 28px;border-bottom:1px solid #1e293b}'
  + '.hdr h1{font-size:22px;font-weight:700;color:#38bdf8}.hdr p{font-size:12px;color:#64748b;margin-top:3px}'
  + '.tags{display:flex;gap:8px;margin-top:10px}.tag{background:#1e293b;border:1px solid #334155;border-radius:5px;padding:3px 10px;font-size:11px;color:#94a3b8}'
  + '.grid{display:grid;grid-template-columns:1fr 1fr;gap:16px;padding:20px 28px}'
  + '.card{background:#1e293b;border:1px solid #334155;border-radius:10px;padding:16px}.full{grid-column:1/-1}'
  + '.card h2{font-size:13px;font-weight:600;color:#38bdf8;margin-bottom:2px}.sub{font-size:10px;color:#64748b;margin-bottom:12px}'
  + 'canvas{max-height:260px}'
  + '.srow{display:flex;align-items:center;gap:8px;padding:5px 0;border-bottom:1px solid #0f172a}'
  + '.sname{width:160px;font-size:11px;color:#94a3b8;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}'
  + '.sbwrap{flex:1;height:14px;background:#0f172a;border-radius:3px;overflow:hidden}'
  + '.sbar{height:100%;border-radius:3px;display:flex;align-items:center;padding-left:4px;font-size:9px;font-weight:700}'
  + '.sp{background:linear-gradient(90deg,#059669,#10b981);color:#d1fae5}.sn{background:linear-gradient(90deg,#dc2626,#ef4444);color:#fee2e2}'
  + '.sval{width:55px;text-align:right;font-size:11px;font-weight:600}'
  + '.sdrvr{font-size:9px;color:#475569;padding:1px 0 5px 168px}'
  + '.sgrid{display:grid;grid-template-columns:repeat(auto-fill,minmax(190px,1fr));gap:8px;margin-top:8px}'
  + '.sc{background:#0f172a;border:1px solid #334155;border-radius:7px;padding:10px}'
  + '.sc .sn2{font-size:11px;font-weight:600;color:#f1f5f9;margin-bottom:5px}'
  + '.bdg{display:inline-block;font-size:9px;padding:2px 7px;border-radius:999px;margin-bottom:3px}'
  + '.bh{background:#7f1d1d;color:#fca5a5}.bm{background:#78350f;color:#fcd34d}'
  + '.sc .amc{font-size:9px;color:#64748b}.sc .wt{font-size:10px;color:#10b981;margin-top:3px}'
  + '.ftr{padding:12px 28px;font-size:10px;color:#475569;text-align:center;border-top:1px solid #1e293b}'
  + '</style></head><body>'
  + '<div class="hdr"><h1>&#127974; MF Intelligence Layer &#8212; Alpha Signal Dashboard</h1>'
  + '<p>Live institutional intelligence from Indian mutual fund portfolio disclosures</p>'
  + '<div class="tags">' + fundsHtml + '</div></div>'
  + '<div class="grid">'
  + '<div class="card"><h2>&#127919; Strategy 1 &#8212; Conviction Clustering</h2><p class="sub">Stocks held &#8805;2% by 2+ AMCs | Score = avg_weight x AMC_count</p><canvas id="c1"></canvas></div>'
  + '<div class="card"><h2>&#128200; Strategy 2 &#8212; Institutional Alpha Basket</h2><p class="sub">Top 10 by cross-fund consensus | 5% equal-weight | Rebalance 15th monthly</p><canvas id="c2"></canvas></div>'
  + '<div class="card full"><h2>&#127754; Strategy 3 &#8212; Sector Rotation Heatmap</h2><p class="sub">Net MF allocation shift by sector | Green = inflow &#183; Red = outflow</p><div id="sbars">' + sectorBarsHtml + '</div></div>'
  + '<div class="card full"><h2>&#128640; Strategy 4 &#8212; New Top-10 Momentum</h2><p class="sub">Stocks newly added to 2+ AMC top holdings | 60-day hold | Apply liquidity filter</p><div class="sgrid" id="scards">' + signalCardsHtml + '</div></div>'
  + '</div>'
  + '<div class="ftr">Generated: ' + generated + ' &nbsp;|&nbsp; Disclaimer: Educational only. Not investment advice.</div>'
  + '<script>'
  + 'Chart.defaults.color="#94a3b8";Chart.defaults.borderColor="#1e293b";'
  + 'var conviction=' + convJson + ';'
  + 'var basket=' + basketJson + ';'
  + 'var sectors=' + sectorsJson + ';'
  + 'var newEntries=' + newJson + ';'
  + 'new Chart(document.getElementById("c1"),{type:"bar",data:{labels:conviction.map(function(s){return s.stock.split(" ").slice(0,2).join(" ");}),datasets:[{label:"Conviction Score",data:conviction.map(function(s){return s.conviction_score;}),backgroundColor:conviction.map(function(s){return s.amc_count>=3?"rgba(56,189,248,0.9)":"rgba(56,189,248,0.5)";}),borderRadius:3},{label:"Confidence/10",data:conviction.map(function(s){return s.confidence/10;}),backgroundColor:"rgba(16,185,129,0.4)",borderRadius:3}]},options:{indexAxis:"y",responsive:true,plugins:{legend:{position:"top",labels:{font:{size:10},boxWidth:10}}},scales:{x:{grid:{color:"#1e293b"}},y:{grid:{color:"#1e293b"},ticks:{font:{size:10}}}}}});'
  + 'new Chart(document.getElementById("c2"),{type:"doughnut",data:{labels:basket.map(function(s){return s.stock.split(" ").slice(0,2).join(" ");}),datasets:[{data:basket.map(function(){return 5;}),backgroundColor:["#0ea5e9","#38bdf8","#7dd3fc","#0284c7","#0369a1","#06b6d4","#22d3ee","#67e8f9","#a5f3fc","#cffafe"],borderColor:"#0f172a",borderWidth:2}]},options:{responsive:true,plugins:{legend:{position:"right",labels:{font:{size:9},boxWidth:10}}},cutout:"60%"}});'
  + '<\/script></body></html>';

return [{ json: { html } }];
